package com.google.gson.internal.bind;
import com.google.gson.JsonElement;
import com.google.gson.JsonPrimitive;
import com.google.gson.JsonSyntaxException;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.internal.$Gson$Types;
import com.google.gson.internal.JsonReaderInternalAccess;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.ObjectConstructor;
import com.google.gson.reflect.TypeToken;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Type;
import java.util.Map;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class MapTypeAdapterFactoryTest {

  @Mock
  private ConstructorConstructor mockConstructorConstructor;

  @Mock
  private Gson mockGson;

  @Mock
  private ObjectConstructor<Object> mockObjectConstructor;

  @Mock
  private TypeAdapter<Object> mockKeyAdapter;

  @Mock
  private TypeAdapter<Object> mockValueAdapter;

  private MapTypeAdapterFactory mapTypeAdapterFactory;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    mapTypeAdapterFactory = new MapTypeAdapterFactory(mockConstructorConstructor, true);
  }

  @Test
  void create_shouldReturnNullIfNotMapType() {
    TypeToken<String> stringTypeToken = TypeToken.get(String.class);

    TypeAdapter<String> adapter = mapTypeAdapterFactory.create(mockGson, stringTypeToken);

    assertNull(adapter);
  }

  @Test
  void create_shouldReturnAdapterForMapType() throws Exception {
    TypeToken<Map<String, String>> mapTypeToken = new TypeToken<Map<String, String>>() {};

    // Mock constructorConstructor.get(TypeToken) to return mockObjectConstructor
    when(mockConstructorConstructor.get(mapTypeToken)).thenReturn((ObjectConstructor) mockObjectConstructor);
    // Mock gson.getAdapter(TypeToken) to return mockValueAdapter
    when(mockGson.getAdapter(TypeToken.get(String.class))).thenReturn((TypeAdapter) mockValueAdapter);

    // Use reflection to inject mockConstructorConstructor into mapTypeAdapterFactory
    Field constructorConstructorField = MapTypeAdapterFactory.class.getDeclaredField("constructorConstructor");
    constructorConstructorField.setAccessible(true);
    constructorConstructorField.set(mapTypeAdapterFactory, mockConstructorConstructor);

    // Use reflection to invoke private getKeyAdapter method
    Method getKeyAdapterMethod = MapTypeAdapterFactory.class.getDeclaredMethod("getKeyAdapter", Gson.class, Type.class);
    getKeyAdapterMethod.setAccessible(true);

    // Mock getKeyAdapter by creating a spy and overriding the method via reflection is complicated,
    // so instead we prepare a spy and use doReturn with a workaround:
    MapTypeAdapterFactory spyFactory = spy(mapTypeAdapterFactory);
    // Override getKeyAdapter using a spy and doAnswer with reflection call fallback
    doAnswer(invocation -> mockKeyAdapter)
        .when(spyFactory, "getKeyAdapter", any(Gson.class), any(Type.class));

    // Since Mockito cannot mock private methods directly, use reflection to invoke getKeyAdapter and verify result
    // But for create(), it calls private getKeyAdapter internally, so we must allow it to call our spy method.
    // The above doAnswer will fail because getKeyAdapter is private.
    // Instead, we can create a subclass to override getKeyAdapter for testing:

    MapTypeAdapterFactory testFactory = new MapTypeAdapterFactory(mockConstructorConstructor, true) {
      @Override
      @SuppressWarnings("unchecked")
      TypeAdapter<?> getKeyAdapter(Gson context, Type keyType) {
        return mockKeyAdapter;
      }
    };

    TypeAdapter<Map<String, String>> adapter = testFactory.create(mockGson, mapTypeToken);

    assertNotNull(adapter);

    // Use reflection to get the Adapter class and check the instance type
    Class<?> adapterClass = null;
    for (Class<?> innerClass : MapTypeAdapterFactory.class.getDeclaredClasses()) {
      if ("Adapter".equals(innerClass.getSimpleName())) {
        adapterClass = innerClass;
        break;
      }
    }
    assertNotNull(adapterClass);
    assertEquals(adapterClass, adapter.getClass());

    // Verify interactions
    verify(mockConstructorConstructor).get(mapTypeToken);
    verify(mockGson).getAdapter(TypeToken.get(String.class));
  }
}
